  "processSteps": [
    {
      "num": 1,
      "title": "Free Consultation",
      "body": "We start with a free, no-obligation consultation — by phone or in person — to understand your situation. We'll explain which type of adoption applies to you, what to expect, and give you a realistic timeline and fee estimate. There's no pressure and no commitment required."
    },
    {
      "num": 2,
      "title": "Engagement & Case Review",
      "body": "Once you decide to move forward, we'll sign an engagement agreement and begin reviewing the details of your case. We gather the necessary information and documents, and advise you on any steps you need to take (such as locating a birth parent or obtaining records)."
    },
    {
      "num": 3,
      "title": "Preparing & Filing the Petition",
      "body": "We prepare all required legal documents, including the Petition for Adoption, and file them with the appropriate Alabama court. Filing fees apply and vary by county. We handle all court paperwork so you don't have to."
    },
    {
      "num": 4,
      "title": "Home Study (When Required)",
      "body": "Most adoptions in Alabama require a home study — an evaluation of your home and background conducted by a licensed agency or social worker. Some stepparent adoptions can waive this requirement. If a home study is required, we'll refer you to a reputable provider and guide you through what to expect."
    },
    {
      "num": 5,
      "title": "Consent & Termination of Parental Rights",
      "body": "Before finalization, the birth parent(s)' rights must be addressed — either through voluntary consent or court-ordered termination. We handle all aspects of this legally sensitive step, ensuring every document is executed correctly and that due process is followed."
    },
    {
      "num": 6,
      "title": "Court Hearing",
      "body": "Alabama adoption finalization requires a court hearing before a judge. We attend with you, present the case, and answer any questions the judge may have. These hearings are typically brief and celebratory! Many clients bring family members and take photos in the courtroom."
    },
    {
      "num": 7,
      "title": "Finalization & New Birth Certificate 🎉",
      "body": "The judge signs the Decree of Adoption — and your family is official! After finalization, we help you obtain a new birth certificate listing the adoptive parent(s) and, if applicable, apply for an updated Social Security record for the child."
    }
  ],
  "processRequirements": [
    {
      "q": "Residency Requirement",
      "a": "At least one party in the adoption must be a resident of Tennessee, or the child must have been in Tennessee for at least 6 months prior to filing."
    },
    {
      "q": "Home Study Requirement",
      "a": "Required in most adoptions unless waived by the court (common in stepparent adoptions). Must be conducted by a licensed Tennessee adoption agency or social worker."
    },
    {
      "q": "Background Check",
      "a": "All prospective adoptive parents must undergo state and federal criminal background checks. Certain prior convictions may disqualify a petitioner under Tennessee law."
    },
    {
      "q": "Consent of the Child",
      "a": "If the child being adopted is 14 years of age or older, they must consent to the adoption in writing."
    },
    {
      "q": "Waiting Period",
      "a": "For private placement and agency adoptions, a statutory waiting period applies before the final hearing. Stepparent adoptions generally have a shorter waiting period."
    }
  ],
